-- 1. 버지니아 한인사회 - 서울대로 표지판
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(47, '애난데일 한인타운에 ''SEOUL BLVD 서울대로'' 한글 도로 표지판 공식 설치', '10년 숙원사업 결실... 연방·지역 정치인 다수 참석', 'annandale-seoul-blvd-sign-2026',
'<p>버지니아주 애난데일 한인타운 존 마 드라이브(John Marr Drive) 일대 3곳에 한글 ''서울''이 새겨진 ''HONORARY SEOUL BLVD'' 표지판이 5월 5일 공식 설치됐다.</p><p>10년간 추진해 온 숙원 사업의 결실로, 설치 현장에는 제임스 워킨쇼 연방 하원의원과 제프 맥케이 페어팩스 카운티 수퍼바이저회 의장 등이 참석했다.</p><p>워킨쇼 의원은 "한인 커뮤니티는 북부 버지니아의 핵심 구성원"이라며 "이 표지판은 한인들의 기여와 문화적 유산을 상징한다"고 축하했다.</p><p>표지판 추진위원회 김동환 위원장은 "2016년부터 시작한 이 프로젝트가 마침내 결실을 맺어 감격스럽다"며 "한인타운의 정체성을 공식적으로 인정받는 역사적 순간"이라고 소감을 밝혔다.</p><p>페어팩스 카운티 공공건설국은 향후 추가 표지판 설치도 검토 중이다.</p>',
'애난데일 한인타운에 한글 ''서울'' 표지판이 공식 설치됐다. 10년 숙원사업의 결실.',
'https://images.unsplash.com/photo-1569982175971-d92b01cf8694?w=800&h=450&fit=crop', 'normal', '김옥채 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T14:00:00+00:00', 0, true, true, 10, now(), now());

-- 2. 한인사회 - 반아시안 혐오범죄 포럼
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(48, '워싱턴 한인사회, 반아시안 혐오범죄 총력 대응 포럼 개최', '5월 15일 알렉산드리아 코리안 커뮤니티 센터에서', 'dc-anti-asian-hate-crime-forum-2026',
'<p>미한기업인친선포럼(AKBFF)과 버지니아 한인회가 5월 15일 알렉산드리아 코리안 커뮤니티 센터에서 ''반아시안 혐오범죄 대응과 예방: 법적 권리와 커뮤니티 협력'' 포럼을 공동 개최한다.</p><p>오후 5시 30분부터 8시까지 진행되는 이번 포럼에는 페어팩스 카운티 경찰국, FBI 워싱턴 지부, 연방검찰 관계자 등이 패널로 참석한다.</p><p>주요 의제는 혐오범죄 신고 절차, 피해자 법적 권리, 커뮤니티 안전망 구축 등이다. 한국어 통역이 제공되며, 참가비는 무료다.</p><p>버지니아 한인회 박상우 회장은 "최근 반아시안 혐오범죄가 다시 증가 추세에 있어 한인사회의 적극적인 대응이 필요하다"고 강조했다.</p>',
'버지니아 한인회, 5월 15일 반아시안 혐오범죄 대응 포럼 개최. FBI·경찰 참석.',
'https://images.unsplash.com/photo-1591696205602-2f950c417cb9?w=800&h=450&fit=crop', 'normal', '이정우 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T13:30:00+00:00', 0, true, true, 8, now(), now());

-- 3. 문화 - 코리안 벨가든 축제
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(49, '제14회 코리안 벨가든 축제, 5월 16일 비엔나에서 개최', '태권도 시범·한식 체험·평화 타종식 등 다채로운 프로그램', 'korean-bell-garden-festival-14th-2026',
'<p>한미문화재단이 5월 16일 오전 11시 비엔나 ''코리안 벨가든''에서 완공 14주년 기념 한국문화행사를 연다.</p><p>워싱턴 글로리아 하프단 공연, 태권도 시범, 평화 타종식, 한식 체험, 전통 혼례복 체험 등이 준비되며 입장료는 무료다.</p><p>코리안 벨가든은 2012년 버지니아 비엔나에 설립된 한국 문화 공간으로, 매년 봄·가을 문화행사를 개최해 지역사회와 한국 문화의 교류에 기여하고 있다.</p><p>한미문화재단 이승호 이사장은 "올해 축제는 한미 수교 기념 특별 프로그램도 준비했다"며 "비한인 주민들도 많이 참여해달라"고 당부했다.</p>',
'한미문화재단, 코리안 벨가든 14주년 기념 축제 개최. 태권도·한식·타종식 등.',
'https://images.unsplash.com/photo-1513151233558-d860c5398176?w=800&h=450&fit=crop', 'normal', '정문화 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T13:00:00+00:00', 0, true, false, 5, now(), now());

-- 4. 한미관계 - 호르무즈 해협
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(50, '외교부 "호르무즈 해협 ''프리덤 프로젝트'' 한미 협의 지속 중"', '국제 해상교통로 안전·항행 자유 원칙 강조', 'korea-hormuz-freedom-project-2026',
'<p>외교부는 트럼프 대통령이 언급한 ''프리덤 프로젝트''와 관련해 국제 해상교통로의 안전과 항행의 자유 원칙을 강조하며 관련 제안을 신중히 검토 중이라고 밝혔다.</p><p>외교부 대변인은 8일 정례 브리핑에서 "한미 양국은 호르무즈 해협을 포함한 주요 해상교통로의 안정적 이용 문제에 대해 긴밀한 소통을 유지하고 있다"고 말했다.</p><p>트럼프 대통령은 지난주 호르무즈 해협의 자유 항행을 보장하기 위한 다국적 해군 작전 구상을 밝힌 바 있으며, 한국의 참여 가능성이 거론되고 있다.</p><p>전문가들은 "한국은 중동 원유 수입 의존도가 높아 호르무즈 해협 안전 문제에 민감할 수밖에 없다"며 "외교적 균형점을 찾는 것이 관건"이라고 분석했다.</p>',
'외교부, 호르무즈 해협 프리덤 프로젝트 관련 한미 협의 중. 항행 자유 원칙 강조.',
'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=800&h=450&fit=crop', 'normal', '김옥채 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T12:30:00+00:00', 0, true, true, 7, now(), now());

-- 5. 한미관계 - 관세 협상
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(51, '한국 산업·통상부 장관, 워싱턴 방문 관세 협상 진행', '럿닉 상무장관·그리어 USTR 대표와 회동', 'korea-trade-ministers-washington-tariff-2026',
'<p>한국 산업부 김 장관과 통상부 여 장관이 워싱턴 DC를 방문해 미 상무장관 럿닉, 무역대표부(USTR) 대표 그리어와 회동했다.</p><p>양측은 한국의 관세 합의 이행 현황을 점검하고 투자 협력 강화 방안을 논의했다. 특히 반도체·배터리·AI 등 첨단 산업 분야에서의 공급망 협력이 주요 의제로 다뤄졌다.</p><p>김 장관은 "한국 기업들의 대미 투자가 지속 확대되고 있으며, 이는 양국 경제 관계를 더욱 공고히 할 것"이라고 강조했다.</p><p>워싱턴 통상 전문가들은 "이번 회동이 한미 FTA 개정 논의의 물꼬를 틀 수 있을지 주목된다"고 평가했다.</p>',
'한국 산업·통상부 장관, 워싱턴서 미 상무장관·USTR 대표와 관세 협상.',
'https://images.unsplash.com/photo-1529107386315-e1a2ed48a620?w=800&h=450&fit=crop', 'normal', '이정우 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T12:00:00+00:00', 0, true, false, 5, now(), now());

-- 6. 국제 - 미중 정상회담
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(52, '트럼프-시진핑 정상회담 앞두고 대만해협 긴장 고조, 한국 외교 기로', '미중 갈등 속 한국의 전략적 균형 모색', 'us-china-summit-taiwan-korea-2026',
'<p>5월 중순 예정된 미중 정상회담을 앞두고 대만 해협의 군사적 긴장이 심각한 수준으로 고조되고 있다.</p><p>중국 인민해방군은 대만 인근 해역에서 대규모 해상 훈련을 실시 중이며, 미국은 항공모함 전단을 서태평양에 증파했다.</p><p>한국은 한미동맹과 대중국 경제 관계 사이에서 전략적 균형을 모색해야 하는 상황이다. 한국의 대중 수출 비중은 여전히 20%를 상회하며, 반도체·배터리 공급망에서 양국 간 협력이 불가피하다.</p><p>워싱턴 소재 전략국제문제연구소(CSIS) 빅터 차 한국석좌는 "한국은 미중 경쟁 속에서 원칙 기반 외교를 유지하면서도 실용적 접근이 필요하다"고 조언했다.</p>',
'미중 정상회담 앞두고 대만해협 긴장 고조. 한국, 한미동맹과 대중 관계 사이 균형 모색.',
'https://images.unsplash.com/photo-1532375810709-75b1da00537c?w=800&h=450&fit=crop', 'normal', '김옥채 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T11:30:00+00:00', 0, true, true, 6, now(), now());

-- 7. 부동산 - DMV 주택시장
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(53, 'DMV 지역 주택시장 금리 상승에 둔화 조짐... 한인 매수 심리 위축', '봄 성수기에도 매물 적체, 30년 고정금리 6% 내외', 'dmv-housing-market-slowdown-may2026',
'<p>워싱턴 수도권(DMV) 주택시장이 금리 상승과 경제 불확실성 여파로 둔화 조짐을 보이고 있다.</p><p>부동산 분석업체 레드핀에 따르면 4월 DMV 지역 주택 중위가격은 전월 대비 0.3% 하락한 56만 2천 달러를 기록했다. 봄철 성수기에도 매수 심리가 살아나지 않으면서 매물 적체와 가격 하락이 동시에 나타나는 양상이다.</p><p>30년 고정 모기지 금리는 6% 내외로 전망되며, 한인 밀집 지역인 센터빌과 애난데일 일대도 거래 위축이 감지되고 있다.</p><p>한인 부동산 전문가 박서영 씨는 "관세 불확실성과 금리 부담이 겹치며 매수 결정을 미루는 한인 고객이 늘었다"고 전했다.</p>',
'DMV 주택시장 봄 성수기에도 둔화. 금리 6% 내외, 한인 매수 심리 위축.',
'https://images.unsplash.com/photo-1560518883-ce09059eeffa?w=800&h=450&fit=crop', 'normal', '박재현 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T11:00:00+00:00', 0, true, false, 0, now(), now());

-- 8. 경제 - IRS 감사 강화
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(54, 'IRS, 한인 비즈니스 대상 고용세 감사 강화... 주의 당부', '정확한 급여 보고·원천징수 기록 관리 중요', 'irs-korean-business-payroll-audit-2026',
'<p>IRS가 한인 비즈니스를 겨냥한 고용세 감사를 강화하고 있어 주의가 요구된다.</p><p>워싱턴 지역 세무 전문가들에 따르면 최근 소규모 한인 자영업체, 특히 음식점·세탁소·뷰티서플라이 등을 대상으로 한 고용세(payroll tax) 감사가 크게 늘었다.</p><p>IRS가 주로 점검하는 항목은 직원 분류(W-2 vs 1099), 팁 소득 보고, 원천징수 기록 등이다. 부정확한 보고 시 과태료와 이자가 부과될 수 있다.</p><p>공인회계사 이대호 씨는 "정확한 급여 보고와 원천징수 기록 관리가 무엇보다 중요하다"며 "의심스러운 IRS 서한을 받으면 즉시 세무 전문가와 상담할 것"을 당부했다.</p>',
'IRS, 한인 소규모 자영업 고용세 감사 강화. 세무 전문가 사전 대비 촉구.',
'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800&h=450&fit=crop', 'normal', '최현수 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T10:30:00+00:00', 0, true, false, 0, now(), now());

-- 9. 경제 - 상속세 면제
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(55, '연방 상속세 면제 한도 인당 $15M으로 영구화... 한인 자산 관리 전략 변화', 'OBBBA 법안 통과, 부부 합산 $30M까지 면세', 'estate-tax-exemption-15m-permanent-2026',
'<p>''하나의 크고 아름다운 법안(OBBBA)'' 통과로 연방 상속세 면제 한도가 인당 1,500만 달러(부부 합산 3,000만 달러)로 상향 및 영구화됐다.</p><p>기존에는 2025년 말 면제 한도가 약 700만 달러로 축소될 예정이었으나, 법안 통과로 고액 자산가들의 상속세 부담이 크게 줄어들 전망이다.</p><p>한인 커뮤니티 재정 전문가들은 이에 따른 자산 관리 전략 재검토를 권고하고 있다. 특히 기존에 상속세 절감을 위해 설정한 신탁(trust) 구조의 필요성을 재평가해야 한다는 조언이 나온다.</p><p>재정 설계사 한정미 씨는 "면제 한도가 올라갔다고 해서 플래닝이 불필요한 것은 아니다"며 "주정부 상속세와 소득세까지 종합적으로 고려해야 한다"고 강조했다.</p>',
'연방 상속세 면제 한도 인당 $15M 영구화. 한인 자산 관리 전략 재검토 필요.',
NULL, 'normal', '최현수 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T10:00:00+00:00', 0, true, false, 0, now(), now());

-- 10. 한인비즈 - 서울대로 상권 효과
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(56, '애난데일 한인 상권, 서울대로 표지판 효과로 활기 기대', '비한인 고객 유입·관광 효과 기대감 확산', 'annandale-seoul-blvd-business-boost-2026',
'<p>애난데일 한인타운에 ''SEOUL BLVD'' 표지판이 설치되면서 지역 한인 상권에 대한 관심이 높아지고 있다.</p><p>한인 상인회는 이번 표지판 설치가 비한인 고객 유입 확대와 관광 효과를 가져올 것으로 기대하고 있다. 이미 SNS에서 표지판과 함께 사진을 찍으려는 방문자가 늘고 있다는 보고가 나오고 있다.</p><p>애난데일 한인상인회 정수현 회장은 "LA 코리아타운처럼 공식적인 한인타운 브랜드가 형성되면 상권 활성화에 큰 도움이 될 것"이라고 기대했다.</p><p>한편 페어팩스 카운티 경제개발청도 애난데일 한인타운을 ''문화 관광 명소''로 홍보하는 방안을 검토 중인 것으로 알려졌다.</p>',
'서울대로 표지판 설치 후 애난데일 한인 상권 활기 기대. 관광 효과 주목.',
NULL, 'normal', '정문화 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T09:30:00+00:00', 0, true, false, 0, now(), now());

-- 11. 교육 - 재미한인장학기금
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(57, '주미대사관, 2026 재미한인장학기금 장학생 88명 선발... 6월 26일까지 접수', '일반 $1,500, 최우수 $5,000 지급', 'embassy-korean-scholarship-88-2026',
'<p>주미대사관이 2026년도 재미한인장학기금(KHS) 장학생 88명(캐나다 7명 포함)을 선발한다.</p><p>일반 선발자에게 1인당 1,500달러, 최우수 장학생 2명에게 각 5,000달러, 우수 장학생 4명에게 각 3,000달러가 지급된다. 6월 26일까지 대학 소재지 관할 총영사관으로 원서를 제출해야 한다.</p><p>지원 자격은 미국 또는 캐나다 소재 정규 4년제 대학에 재학 중인 한국 국적자 또는 한인 후손으로, GPA 3.0 이상이어야 한다.</p><p>주미대사관 관계자는 "재미한인장학기금은 차세대 한인 인재 양성의 중요한 디딤돌"이라며 적극적인 지원을 당부했다.</p>',
'주미대사관, 재미한인장학기금 장학생 88명 선발. 6월 26일 마감.',
'https://images.unsplash.com/photo-1523050854058-8df90110c9f1?w=800&h=450&fit=crop', 'normal', '김윤미 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T09:00:00+00:00', 0, true, false, 3, now(), now());

-- 12. 교육 - 한국어 수업
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(58, '워싱턴 한국교육원, 여름학기 한국어 수업 등록 개시', '초급~고급 다양한 레벨, 비한인 학습자도 환영', 'korean-education-center-summer-2026',
'<p>워싱턴 한국교육원이 2026년 여름학기 한국어 수업 등록을 개시했다.</p><p>초급부터 고급까지 다양한 레벨의 수업이 제공되며, 재미동포 자녀와 비한인 학습자 모두 신청 가능하다. K-드라마와 K-POP의 인기에 힘입어 비한인 수강생 비율이 매년 증가하고 있다.</p><p>이번 여름학기에는 한국 문화 체험 수업, 한국어 능력시험(TOPIK) 대비반도 신설됐다. 수업은 6월 중순부터 8월 중순까지 10주간 진행된다.</p><p>한국교육원 최영훈 원장은 "한국어 교육은 동포 자녀의 정체성 확립뿐 아니라 한미 문화 교류의 핵심"이라고 강조했다.</p>',
'워싱턴 한국교육원 여름학기 한국어 수업 등록 시작. TOPIK 대비반 신설.',
NULL, 'normal', '김윤미 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T08:30:00+00:00', 0, true, false, 0, now(), now());

-- 13. 교육 - 한국어 말하기 대회
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(59, '버지니아 한인학교 협의회, 제15회 한국어 말하기 대회 참가자 모집', '초등부·중고등부 나눠 진행', 'virginia-korean-speech-contest-15th-2026',
'<p>워싱턴한국학교협의회가 제15회 한국어 말하기 대회 참가자를 모집하고 있다.</p><p>초등부와 중고등부로 나뉘어 진행되며, 한인 2세 자녀들의 한국어 능력 향상과 정체성 확립을 위한 행사로 매년 큰 호응을 얻고 있다.</p><p>대회는 6월 첫째 주 토요일 페어팩스 소재 한인교회에서 개최될 예정이며, 참가 신청은 5월 25일까지다. 수상자에게는 장학금과 상장이 수여된다.</p><p>협의회 관계자는 "미국에서 나고 자란 한인 자녀들이 한국어로 자신의 생각을 표현하는 귀한 기회"라며 많은 참여를 독려했다.</p>',
'제15회 한국어 말하기 대회 참가자 모집. 5월 25일 마감, 6월 개최.',
NULL, 'normal', '정문화 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T08:00:00+00:00', 0, true, false, 0, now(), now());

-- 14. 이민비자 - 5월 비자 불레틴
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(60, '5월 비자 불레틴 발표... 취업이민 카테고리 전진 중단', 'EB 카테고리 Dates for Filing 적용 보류', 'may-2026-visa-bulletin-eb-freeze',
'<p>미 국무부가 2026년 5월 비자 불레틴을 발표했다. 수개월간의 전진 이후 취업이민(EB) 카테고리에서 전진이 중단됐다.</p><p>특히 EB-2와 EB-3 카테고리에서 접수일자(Dates for Filing) 적용이 보류되면서 많은 한인 이민 신청자들에게 영향을 미칠 전망이다.</p><p>가족이민 카테고리는 대부분 소폭 전진을 이어가고 있으나, F2B(영주권자 미혼 성인 자녀) 카테고리는 후퇴했다.</p><p>이민 변호사 김한솔 씨는 "전진 중단은 일시적일 수 있지만, 대기 중인 신청자들은 대안 경로도 검토할 필요가 있다"고 조언했다.</p>',
'5월 비자 불레틴: 취업이민 전진 중단, Dates for Filing 보류. 한인 이민자 영향.',
'https://images.unsplash.com/photo-1436491865332-7a61a109db05?w=800&h=450&fit=crop', 'normal', '이정우 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T07:30:00+00:00', 0, true, false, 3, now(), now());

-- 15. 이민비자 - H-1B 추첨
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(61, '한국인 H-1B 비자 신청자, 2026년 추첨 결과 발표', 'EB-1A, EB-2 NIW 등 대안 경로 검토 권고', 'h1b-visa-lottery-result-korean-2026',
'<p>2026년도 H-1B 비자 추첨 결과가 발표됐다. 한국 국적자의 H-1B는 기술·공학·과학 분야에서 가장 보편적인 취업이민 경로로, 올해도 높은 경쟁률을 기록했다.</p><p>USCIS에 따르면 올해 H-1B 신청 건수는 약 48만 건으로 전년 대비 10% 증가했으며, 당첨률은 약 17%에 그쳤다.</p><p>이민 전문가들은 추첨에 탈락한 한국인 신청자들에게 EB-1A(특출한 능력), EB-2 NIW(국익 면제) 등 대안 경로도 적극 검토할 것을 권고하고 있다.</p><p>워싱턴 소재 이민법률사무소 관계자는 "H-1B 의존도를 줄이고 다양한 이민 경로를 탐색하는 것이 현명하다"고 조언했다.</p>',
'H-1B 비자 추첨 경쟁률 역대 최고. 이민 전문가들, 대안 경로 검토 권고.',
NULL, 'normal', '이정우 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T07:00:00+00:00', 0, true, false, 0, now(), now());

-- 16. 이민 - 한국 Top-Tier 비자
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(62, '한국 법무부, ''Top-Tier 비자'' 자격 확대 및 E-7-M 비자 신설', '재미한인의 한국 취업 기회 확대 전망', 'korea-top-tier-visa-e7m-2026',
'<p>한국 법무부가 포괄적 이민정책 개편을 발표했다. Top-Tier 비자 자격이 과학기술 분야 교수와 연구자까지 확대됐으며, 제조업 중급 기술인력을 위한 E-7-M 비자가 신설됐다.</p><p>Top-Tier 비자는 고급 인재 유치를 위한 한국의 전략적 비자 프로그램으로, 기존 IT·금융 분야에서 바이오·에너지·반도체 연구 분야로 대상이 넓어졌다.</p><p>재미한인의 한국 취업 기회도 넓어질 전망이다. 특히 미국에서 학위를 취득한 한인 2세들의 한국 취업 수요가 증가하고 있어 주목된다.</p><p>워싱턴 한인 이민 전문가는 "한국의 인구 감소 대응 차원에서 재외동포 인재 유치가 더욱 강화될 것"이라고 전망했다.</p>',
'한국 Top-Tier 비자 확대, E-7-M 신설. 재미한인 한국 취업 기회 확대.',
'https://images.unsplash.com/photo-1517048676732-d65bc937f952?w=800&h=450&fit=crop', 'normal', '김옥채 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T06:30:00+00:00', 0, true, false, 0, now(), now());

-- 17. 문화/종교 - 어버이날
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(63, '5월 가정의 달 맞아 DMV 한인교회 어버이날 특별 예배 잇따라', '한인 시니어 축하 공연·식사 행사도', 'dmv-korean-church-parents-day-2026',
'<p>5월 가정의 달을 맞아 워싱턴 수도권(DMV) 지역 한인교회들이 어버이날(5월 8일) 특별 예배와 감사 행사를 잇따라 개최하고 있다.</p><p>센터빌 소재 워싱턴중앙장로교회는 8일 오전 예배에서 70세 이상 어르신들께 카네이션을 달아드리고 축하 떡을 나눴다. 페어팩스 제일침례교회는 어버이 감사 음악회를 열어 호응을 얻었다.</p><p>한인 시니어를 위한 축하 공연과 식사 행사도 함께 마련됐다. 워싱턴 한인노인회는 이날 노인 130여 명을 초청해 점심 식사와 공연 관람 행사를 진행했다.</p><p>한인 교계 관계자는 "이민 생활의 어려움 속에서도 어르신들의 헌신에 감사하는 뜻깊은 자리"라고 전했다.</p>',
'DMV 한인교회, 어버이날 특별 예배·감사 행사 잇따라. 시니어 축하 공연도.',
'https://images.unsplash.com/photo-1511895426328-dc8714191300?w=800&h=450&fit=crop', 'normal', '정문화 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T06:00:00+00:00', 0, true, false, 0, now(), now());

-- 18. 문화 - 미술 작품전
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(64, '워싱턴 한인 미술협회, ''봄의 서사'' 작품전 개최', '5월 10일~24일, 듀폰 서클 갤러리에서 40여 점 전시', 'dc-korean-art-spring-narratives-2026',
'<p>워싱턴 한인 미술협회가 5월 10일부터 24일까지 듀폰 서클 인근 갤러리에서 ''봄의 서사: Spring Narratives'' 회원 작품전을 개최한다.</p><p>회화, 사진, 설치미술 등 다양한 장르의 작품 40여 점이 전시된다. 이번 전시는 ''이민과 봄, 새로운 시작''이라는 주제로 15명의 한인 작가가 참여한다.</p><p>개막식은 5월 10일 오후 5시에 열리며, 작가와의 대화 세션도 마련된다. 관람료는 무료다.</p><p>미술협회 김선아 회장은 "한인 예술가들의 목소리를 주류 사회에 알리는 좋은 기회"라며 많은 방문을 독려했다.</p>',
'한인 미술협회 ''봄의 서사'' 작품전. 듀폰 서클 갤러리, 5월 10~24일.',
'https://images.unsplash.com/photo-1531913764164-f85c3e01b2aa?w=800&h=450&fit=crop', 'normal', '정문화 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T05:30:00+00:00', 0, true, false, 0, now(), now());

-- 19. 커뮤니티 - 어린이 문화 체험
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(65, '메릴랜드 한인회, 5월 18일 어린이 한국문화 체험의 날 개최', '한복 입기·전통놀이·K-POP 댄스·한글 서예 등', 'maryland-korean-culture-day-kids-2026',
'<p>메릴랜드 한인회가 5월 18일 록빌 시민센터에서 ''어린이 한국문화 체험의 날''을 개최한다.</p><p>한복 입기, 전통 놀이, K-POP 댄스, 한글 서예 체험 등 다채로운 프로그램이 준비되어 있으며, 한인 2세 자녀의 정체성 교육을 목표로 한다.</p><p>이번 행사에는 비한인 어린이들도 참여할 수 있으며, 한국 전통 간식과 기념품도 제공된다. 참가비는 가족당 10달러다.</p><p>메릴랜드 한인회 최수진 회장은 "미국에서 자라는 우리 아이들이 한국 문화에 자연스럽게 노출되는 것이 중요하다"고 취지를 설명했다.</p>',
'메릴랜드 한인회, 어린이 한국문화 체험의 날. 록빌 시민센터, 5월 18일.',
'https://images.unsplash.com/photo-1544776193-352d25ca82cd?w=800&h=450&fit=crop', 'normal', '김윤미 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T05:00:00+00:00', 0, true, false, 0, now(), now());

-- 20. 건강 - 건강보험 감소
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(66, 'DMV 한인 건강보험 가입자 감소세... 전년 대비 13% 줄어', '약 3만 6,500명 보험 해지, 제도 도입 이후 최대 감소', 'dmv-korean-health-insurance-decline-2026',
'<p>2026년 DMV 지역 건강보험 가입자가 약 25만 명으로 전년 대비 약 13% 감소했다. 약 3만 6,500명이 보험을 해지한 것으로 나타났으며, 이는 건강보험 마켓플레이스 도입 이후 최대 감소폭이다.</p><p>감소 원인으로는 보험료 인상, 메디케이드 재검증에 따른 자격 상실, 경제적 어려움 등이 꼽힌다. 한인 커뮤니티 의료 단체들은 무보험 한인이 늘어나는 것에 우려를 표하고 있다.</p><p>한인건강센터 이미연 소장은 "건강보험이 없으면 응급 상황에서 막대한 의료비 부담을 떠안게 된다"며 "보험 유지의 중요성을 아무리 강조해도 지나치지 않다"고 말했다.</p>',
'DMV 건강보험 가입자 13% 감소, 최대 감소폭. 한인 무보험자 증가 우려.',
NULL, 'normal', '박재현 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T04:30:00+00:00', 0, true, false, 0, now(), now());

-- 21. 건강 - 시니어 건강 박람회
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(67, '한인 시니어 건강 박람회, 5월 20일 센터빌에서 개최', '무료 혈압·혈당 검사, 치매 선별검사, 메디케어 상담', 'korean-senior-health-fair-centreville-2026',
'<p>버지니아 한인 노인회와 페어팩스 카운티 보건국이 공동으로 5월 20일 센터빌 한인커뮤니티센터에서 한인 시니어 건강 박람회를 개최한다.</p><p>무료 혈압·혈당 검사, 치매 선별검사, 메디케어 상담, 영양 상담 등이 제공된다. 한국어 통역이 배치되어 의사소통에 불편이 없도록 했다.</p><p>올해는 한인 시니어들의 관심이 높은 당뇨병 관리, 관절염 예방, 정신건강 상담 부스도 새로 마련됐다.</p><p>한인 노인회 김영호 회장은 "한인 어르신들이 언어 장벽 없이 건강 검진을 받을 수 있는 소중한 기회"라고 강조했다.</p>',
'한인 시니어 건강 박람회 5월 20일 센터빌. 무료 검사·메디케어 상담 제공.',
'https://images.unsplash.com/photo-1576091160550-2173dba999ef?w=800&h=450&fit=crop', 'normal', '박재현 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T04:00:00+00:00', 0, true, false, 0, now(), now());

-- 22. 사건사고 - 텍사스 총격
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(68, '텍사스 캐롤턴 K타운 플라자 총격사건, 한인사회 충격', '워싱턴 한인단체, 피해자 지원 모금·총기 규제 촉구', 'texas-carrollton-ktown-shooting-2026',
'<p>5월 5일 오전 텍사스 캐롤턴 K타운 플라자에서 비극적인 총격 사건이 발생해 미주 한인사회에 큰 충격을 주고 있다.</p><p>현지 경찰에 따르면 이날 오전 10시경 K타운 플라자 내 한인 미용실에서 총격이 발생해 3명이 부상을 입고 병원으로 이송됐다. 용의자는 현장에서 체포됐다.</p><p>워싱턴 한인단체들도 피해자 가족 지원 모금과 총기 규제 강화를 촉구하는 성명을 발표했다. 버지니아 한인회는 "한인 밀집 상권의 안전 대책 마련이 시급하다"며 관계 기관과의 협력을 강화하겠다고 밝혔다.</p><p>미주한인총연합회도 전국 한인 상권 안전 점검 캠페인을 시작한다고 발표했다.</p>',
'텍사스 K타운 플라자 총격사건 한인사회 충격. 워싱턴 한인단체 지원 모금 나서.',
'https://images.unsplash.com/photo-1453873531674-2151bcd01707?w=800&h=450&fit=crop', 'normal', '이정우 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T03:30:00+00:00', 0, true, true, 4, now(), now());

-- 23. 스포츠 - 월드컵 응원전
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(69, '2026 월드컵 워싱턴 공동응원전 준비위원회 발대식', '개막 약 40일 앞두고 역대 최대 규모 한인 응원전 준비', 'worldcup-2026-dc-cheering-committee-2026',
'<p>2026 북중미 월드컵 개막을 약 40일 앞두고 워싱턴 한인사회가 공동응원전 준비에 박차를 가하고 있다.</p><p>버지니아 한인회 주최로 기금마련 골프대회가 열렸으며, 역대 최대 규모의 한인 응원전을 준비 중이다. 응원전은 워싱턴 DC 인근 대형 행사장에서 대형 스크린을 설치해 진행될 예정이다.</p><p>준비위원회 이강호 위원장은 "한국 대표팀의 16강 이상 진출을 기원하며, 한인사회가 하나로 뭉치는 축제의 장을 만들겠다"고 포부를 밝혔다.</p><p>한국은 E조에 배정되어 우루과이, 이란, 카메룬과 조별 리그를 치른다.</p>',
'2026 월드컵 워싱턴 공동응원전 준비 본격화. 역대 최대 규모 계획.',
'https://images.unsplash.com/photo-1431324155629-1a6deb1dec8d?w=800&h=450&fit=crop', 'normal', '김옥채 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T03:00:00+00:00', 0, true, false, 3, now(), now());

-- 24. 시민참여 - CKA 펠로우십
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(70, 'CKA, 2026 차세대 리더십 펠로우십 모집 마감... 경쟁률 역대 최고', '10주 리더십 프로그램, 워싱턴 DC에서 진행', 'cka-emerging-leaders-fellowship-2026',
'<p>미주한인협의회(Council of Korean Americans)의 2026 Emerging Leaders Fellowship 모집이 5월 1일 마감됐다.</p><p>차세대 한인 디아스포라를 위한 10주 리더십 프로그램으로 매년 워싱턴 DC에서 진행된다. 올해 지원자 수는 전년 대비 35% 증가해 역대 최고 경쟁률을 기록했다.</p><p>프로그램은 정책 입안, 시민 참여, 리더십 개발 등을 다루며, 연방 의회와 행정부 관계자와의 네트워킹 기회도 제공된다.</p><p>CKA 에이브러햄 김 대표는 "한인 차세대가 미국 정치와 공공 분야에서 목소리를 높이는 것이 그 어느 때보다 중요한 시기"라고 강조했다.</p>',
'CKA 차세대 펠로우십 역대 최고 경쟁률. 워싱턴 DC 10주 리더십 프로그램.',
NULL, 'normal', '김윤미 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T02:30:00+00:00', 0, true, false, 0, now(), now());

-- 25. 한인사회 - 서재필 기념관
INSERT INTO joongang_articles (article_number, title, subtitle, slug, content, excerpt, thumbnail_url, article_type, author_name, source_name, status, is_published, published_at, view_count, allow_comments, is_featured, priority, created_at, updated_at) VALUES
(71, '워싱턴한인회, 서재필 기념관 방문 행사 성료', '한인 문화유산 보존 사업 협력 다짐', 'washington-korean-seo-jaepil-memorial-2026',
'<p>워싱턴한인회가 5월 2일 서재필 기념관 방문 행사를 성공적으로 개최했다.</p><p>버지니아한인회, 메릴랜드한인회, 한인커뮤니티센터, 워싱턴한국학교협의회 등이 협업하여 한인 문화유산 보존 사업을 이어가고 있다.</p><p>서재필(Philip Jaisohn) 박사는 최초의 한국계 미국 시민권자이자 독립운동가로, 필라델피아에 기념관이 있다. 이번 방문에는 워싱턴 지역 한인 60여 명이 참가했다.</p><p>워싱턴한인회 박영진 회장은 "우리 선조들의 역사를 기억하고 다음 세대에 전달하는 것은 한인사회의 책무"라며 "매년 이 같은 행사를 지속하겠다"고 밝혔다.</p>',
'워싱턴한인회, 서재필 기념관 방문 행사 성료. 한인 문화유산 보존 다짐.',
'https://images.unsplash.com/photo-1524492412937-b28074a5d7da?w=800&h=450&fit=crop', 'normal', '정문화 기자', '중앙일보 워싱턴', 'published', true, '2026-05-08T02:00:00+00:00', 0, true, false, 0, now(), now());


